import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as s,a as e}from"./app-b3ace9bd.js";const t="/assets/images/vasvari/InputEvents.webp",o="/assets/images/vasvari/EventFiltersFiring.webp",l="/assets/images/vasvari/MouseEventJavaFXv2.webp",p={},c=e('<h1 id="events" tabindex="-1"><a class="header-anchor" href="#events" aria-hidden="true">#</a> Events</h1><p>A <strong>JavaFX</strong> felhasználói felületei szinte teljesen eseményvezéreltek. A legtöbb ember ismeri a műveleti eseményeket, a billentyű- és egéreseményeket, de a felhasználói felület szinte minden összetett frissítése valamilyen esemény segítségével történik. És mégis, az események a <strong>JavaFX</strong> egyik legkevésbé kihangsúlyozott része.</p><h2 id="a-javafx-esemenyek-utmutatoja" tabindex="-1"><a class="header-anchor" href="#a-javafx-esemenyek-utmutatoja" aria-hidden="true">#</a> A JavaFX események útmutatója</h2><p>Általános szabályként elmondható, hogy ha egyszerű érték alapú változtatást kell végrehajtani, akkor ezt Property kötéssel lehet elérni. Minden egyéb esetben érdemes eseményeket használni. Az események sokoldalúak és stabil módot biztosítanak a változások vezérlésére az alkalmazásban.</p><p>Eseménynek számít bármely állapotváltozás egy bemeneti eszközön (<em>például egér vagy érintőképernyő</em>), egy felhasználói művelet (<code>ActionEvent</code>) vagy egy háttérfeladat során. Az események összetett csomópontok, például <code>TableView</code>-ben és <code>ListView</code>-ben történő görgetés vagy szerkesztés eredményeként is kiválthatunk.</p><p>Nagyon alapszinten az <code>Event</code> objektum egy osztály, meglepően kevés paraméterrel. Nem tartalmaz semmilyen futtatható kódot, és nem is futtat semmilyen kódot. Ez egy jelzés a rendszernek, hogy valami megváltozott.</p><p>A JavaFX jelentős támogatást nyújt a végrehajtható kódok futtatásához, amelyeket külön az <code>EventHandler</code> osztályon keresztül definiálnak, minden állapotváltozás esetén.A JavaFX <em>90</em> különálló eseménytípust támogat, és lehetőség van az <code>Event</code> osztály kiterjesztésére és további egyéni funkciók definiálására.</p><h3 id="hogyan-mukodnek-az-esemenyek" tabindex="-1"><a class="header-anchor" href="#hogyan-mukodnek-az-esemenyek" aria-hidden="true">#</a> Hogyan működnek az események?</h3><p>Nem hazudok, ha azt mondom, hogy egy <code>Event</code> rendkívül egyszerű. Ami bonyolult, az a háttérben futó folyamatok, amelyek megvalósítják az eseménykezelő rendszert. Ebben a szakaszban áttekintjük, mi határozza meg egy <code>Event</code>-et, és hogyan állíthatjuk be a kódunkat, hogy minden alkalommal végrehajtsa, amikor egy bizonyos eseményt észlel.</p><h2 id="az-event-osztaly" tabindex="-1"><a class="header-anchor" href="#az-event-osztaly" aria-hidden="true">#</a> Az Event osztály</h2><p>A JavaFX-ben egy Eseménynek négy tulajdonsága van:</p><ul><li>Forrás (<code>Source</code>)</li><li>Cél (<code>Target</code>)</li><li>Típus (<code>Type</code>)</li><li>Felhasználva (<code>consumed</code>)</li></ul><h3 id="source" tabindex="-1"><a class="header-anchor" href="#source" aria-hidden="true">#</a> Source</h3><p>JavaFX a <code>Node</code>-ot rendeli hozzá az esemény forrásaként a létrehozásnál, ami az esemény okának megfelelően van meghatározva. (<em>egér, billentyű, művelet stb.</em>).</p><p>A Java natívan támogatja az eseményeket az <code>EventObject</code> osztállyal. Még mielőtt a <strong>JavaFX</strong> a saját <code>Target</code> és <code>Type</code> attribútumait is rárakná, az esemény alapvető része a forrás. A <code>Target</code>, a <code>Type</code> és a <code>Consumed</code> a <strong>JavaFX</strong> által bevezetett konstrukciók, de minden eseményt valaminek ki kell váltania.</p><p>Az eseményforrás az az objektum, amely az eseményt okozza. Sokféle állapotváltozás okozhat eseményt:</p><ul><li>Az egér mozgása, kattintás, húzás</li><li>gesztusok, érintőképernyő bevitele, nagyítás.</li><li>Egy gomb aktiválása</li><li>Egy feladat elindulása, befejezése vagy állapotváltozása.</li></ul><p>Még akkor is, ha egy bemeneti eszközről van szó, amelynek állapota megváltozott, a <strong>JavaFX</strong> hozzárendeli a saját forrását, amely gyakran egy csomópont.</p><p>E rugalmasság érdekében az esemény forrása <code>Object</code>-ként tárolódik, és a <code>getSource()</code> metóduson keresztül érhető el.</p><h3 id="target" tabindex="-1"><a class="header-anchor" href="#target" aria-hidden="true">#</a> Target</h3><p>A <strong>JavaFX</strong> kiterjeszti a <code>java.util</code> fájlban szereplő <code>EventObject</code>-et, hogy további paramétereket adjon hozzá. Ezek közül az első a <code>target</code>, amely azt a <code>Node</code>-ot határozza meg, amelyre az esemény hatott. Például, amikor egy <code>TextField</code> mezőbe gépelünk, minden billentyűleütés <code>KeyEvent</code>-ként regisztrálódik, és minden ilyen esemény célpontja a <code>TextField</code> mező lesz.</p><figure><img src="'+t+`" alt="A JavaFX kiterjeszti a Java  osztályt a specifikus eseménytípusok és az  paraméter hozzáadásához." tabindex="0" loading="lazy"><figcaption>A JavaFX kiterjeszti a Java <code>EventObject</code> osztályt a specifikus eseménytípusok és az <code>EventTarget</code> paraméter hozzáadásához.</figcaption></figure><p>Az <code>EventObject</code> kiterjesztése rugalmasságot biztosít a <strong>JavaFX</strong> számára az esemény céljának <strong>JavaFX</strong>-specifikus módon történő tárolásához és megadásához. Ebben az esetben a <strong>JavaFX</strong>-ben bármely esemény céljának implementálnia kell az <code>EventType</code> interfészt. Ez az interfész egyetlen metódust tartalmaz, amely paraméterként egy <code>EventDispatchChain</code>-t fogad, és egy <code>EventDispatchChain</code>-t ad vissza.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token class-name">EventDispatchChain</span> <span class="token function">buildEventDispatchChain</span><span class="token punctuation">(</span><span class="token class-name">EventDispatchChain</span> tail<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ez áll a <strong>JavaFX</strong> eseménykezelési módjának középpontjában. Rengeteg <strong>JavaFX</strong> objektum bővíti az <code>EventTarget</code> interfészt:</p><ul><li><strong>Nodes, Panes and Controls</strong> <i class="fa-solid fa-window-maximize"></i></li><li><strong>Transforms</strong> <i class="fa-solid fa-rotate"></i></li><li><strong>Charts</strong> <i class="fa-solid fa-chart-line"></i></li><li><strong>Lights and Cameras</strong> <i class="fa-solid fa-lightbulb"></i></li><li><strong>Mesh data</strong> <i class="fa-solid fa-layer-group"></i></li><li><strong>Shapes</strong> <i class="fa-solid fa-shapes"></i></li><li><strong>Skins</strong> <i class="fa-regular fa-file-code"></i></li></ul><p>Ez lehetővé teszi a <strong>JavaFX</strong> számára, hogy a felhasználói felület bármely elemén eseményeket indítson, de nekünk, fejlesztőknek is lehetővé teszi, hogy ezeket az eseményeket indítsuk.</p><p>Mivel az eseményeket a <strong>JavaFX</strong> így kezeli, azt is biztosítja, hogy az általunk megadott végrehajtható kódot az <code>Application</code> szálon küldjük el. Ez egy hihetetlenül stabil módja az olyan összetett elemek, mint a diagramok és a vizuálisan bonyolult vezérlők frissítésének.</p><h3 id="type" tabindex="-1"><a class="header-anchor" href="#type" aria-hidden="true">#</a> Type</h3><p>A JavaFX az eseménytípust az esemény eredete (<em>egér, billentyű, művelet stb.</em>) és az állapotváltozás jellege (<em>billentyű elengedése, egérkattintás, feladat elindítása stb.</em>) alapján jelöli ki.</p><p>Az eseménytípusok az <code>EventType</code> osztály által meghatározott <strong>JavaFX</strong>-specifikus paraméterek. Tudomásom szerint a JavaFX két okból definiálja az eseménytípusokat az <code>EventType</code> osztály segítségével:</p><h4 id="tipusbiztonsag" tabindex="-1"><a class="header-anchor" href="#tipusbiztonsag" aria-hidden="true">#</a> Típusbiztonság</h4><p>Egy <code>EventType</code> meghatározásakor meg kell adnia az eseményt, amelyre a típust definiálja, és meg kell adnia az esemény nevét. A <strong>JavaFX</strong> <code>90</code> előre definiált eseménytípussal rendelkezik, amelyek az <code>Event</code> és az <code>al-Event</code> osztályok statikus tagváltozóiként érhetők el.</p><div class="hint-container note"><p class="hint-container-title">Különbség az AWT-től</p><h4 id="" tabindex="-1"><a class="header-anchor" href="#" aria-hidden="true">#</a></h4><p>A <strong>Java</strong> másik ablakkezelő megoldása az absztrakt ablakkezelő eszközkészlet (<code>AWT</code>). Az események típusbiztonságát ebben az eszközkészletben úgy érték el, hogy az eseményeket egész számokként adták meg.</p><p>Ez nem tökéletes típusbiztonság, de statikus tagváltozóként lettek definiálva, mint például <code>MOUSE_CLICKED = 500</code>, így legalább könnyen lehetett rájuk hivatkozni.</p><p>Ha a <strong>JavaFX</strong> is ezt tette volna, a <code>MouseEvent.MOUSE_CLICKED</code> (<code>AWT import</code>) és a <code>MouseEvent.MOUSE_CLICKED</code> (<code>JavaFX import</code>) elég nehezen lenne észrevehető. Ha a statikus változók mögötti számok különbözőek lennének, talán észre sem vennéd, amíg a kódod össze nem omlik, és kézzel kell hibátkeresned.</p></div><h3 id="consumed" tabindex="-1"><a class="header-anchor" href="#consumed" aria-hidden="true">#</a> consumed</h3><p>Bármely ponton ebbe a folyamatban, beleértve azt is, mielőtt az esemény elérte volna a célját, az eseményt kezelni lehet.</p><p>A <strong>JavaFX</strong> eseménykezelésének alapvető része, hogy az események a <code>SceneGraph</code>-on haladnak. Egy <code>Node</code> csomóponton bekövetkező esemény a tetején lévő <strong>Window</strong>-tól halad lefelé a csomópontig, majd vissza felfelé.</p><p>Az eseményt végrehajtásának egy részénél dolgozzuk fel (<code>.consume()</code>), akkor az azonnal leáll, és további események nem hívódnak meg.</p><p>Lehetőség van egy esemény leállítására, mielőtt az elérné a célcsomópontot. Ez az eseményszűrők gyakori felhasználási módja.</p><p>Az eseményeket a <code>consume()</code> metódussal lehet felhasználni.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">package</span> <span class="token namespace">org<span class="token punctuation">.</span>vasvari<span class="token punctuation">.</span>helloworld</span><span class="token punctuation">;</span>

<span class="token keyword">import</span> <span class="token import"><span class="token namespace">javafx<span class="token punctuation">.</span>application<span class="token punctuation">.</span></span><span class="token class-name">Application</span></span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token import"><span class="token namespace">javafx<span class="token punctuation">.</span>scene<span class="token punctuation">.</span>control<span class="token punctuation">.</span></span><span class="token class-name">Alert</span></span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token import"><span class="token namespace">javafx<span class="token punctuation">.</span>scene<span class="token punctuation">.</span>control<span class="token punctuation">.</span></span><span class="token class-name">Alert</span><span class="token punctuation">.</span><span class="token class-name">AlertType</span></span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token import"><span class="token namespace">javafx<span class="token punctuation">.</span>scene<span class="token punctuation">.</span>control<span class="token punctuation">.</span></span><span class="token class-name">ButtonType</span></span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token import"><span class="token namespace">javafx<span class="token punctuation">.</span>stage<span class="token punctuation">.</span></span><span class="token class-name">Stage</span></span><span class="token punctuation">;</span>

<span class="token keyword">import</span> <span class="token import"><span class="token namespace">java<span class="token punctuation">.</span>util<span class="token punctuation">.</span></span><span class="token class-name">Optional</span></span><span class="token punctuation">;</span>

<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Main</span> <span class="token keyword">extends</span> <span class="token class-name">Application</span> <span class="token punctuation">{</span>
    <span class="token annotation punctuation">@Override</span>
    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">start</span><span class="token punctuation">(</span><span class="token class-name">Stage</span> primaryStage<span class="token punctuation">)</span> <span class="token punctuation">{</span>

        primaryStage<span class="token punctuation">.</span><span class="token function">setOnCloseRequest</span><span class="token punctuation">(</span>e <span class="token operator">-&gt;</span> <span class="token punctuation">{</span>
            <span class="token class-name">Alert</span> confirm <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Alert</span><span class="token punctuation">(</span><span class="token class-name">AlertType</span><span class="token punctuation">.</span><span class="token constant">CONFIRMATION</span><span class="token punctuation">,</span> <span class="token keyword">null</span><span class="token punctuation">,</span> <span class="token class-name">ButtonType</span><span class="token punctuation">.</span><span class="token constant">YES</span><span class="token punctuation">,</span> <span class="token class-name">ButtonType</span><span class="token punctuation">.</span><span class="token constant">NO</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
            confirm<span class="token punctuation">.</span><span class="token function">setTitle</span><span class="token punctuation">(</span><span class="token string">&quot;Biztosan ki akar lépni?&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
            confirm<span class="token punctuation">.</span><span class="token function">setHeaderText</span><span class="token punctuation">(</span><span class="token string">&quot;Biztosan ki akar lépni?&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

            <span class="token class-name">Optional</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">ButtonType</span><span class="token punctuation">&gt;</span></span> answer <span class="token operator">=</span> confirm<span class="token punctuation">.</span><span class="token function">showAndWait</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

            <span class="token keyword">if</span> <span class="token punctuation">(</span>answer<span class="token punctuation">.</span><span class="token function">isPresent</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">&amp;&amp;</span> answer<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">==</span> <span class="token class-name">ButtonType</span><span class="token punctuation">.</span><span class="token constant">NO</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
                e<span class="token punctuation">.</span><span class="token function">consume</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
            <span class="token punctuation">}</span>
        <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

        primaryStage<span class="token punctuation">.</span><span class="token function">setWidth</span><span class="token punctuation">(</span><span class="token number">400</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        primaryStage<span class="token punctuation">.</span><span class="token function">setHeight</span><span class="token punctuation">(</span><span class="token number">400</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        primaryStage<span class="token punctuation">.</span><span class="token function">show</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

    <span class="token punctuation">}</span>

    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token function">launch</span><span class="token punctuation">(</span>args<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="esemenykivaltodasi-fazisok" tabindex="-1"><a class="header-anchor" href="#esemenykivaltodasi-fazisok" aria-hidden="true">#</a> Eseménykiváltódási fázisok</h2><p>Amikor egy esemény kiváltódik a <strong>JavaFX</strong>-ben, az a jelenettől (<code>Scene</code>) a csomópontig (<code>Node</code>), majd a csomóponttól vissza a jelenetig utazik.</p><p>Ehhez három dologra van szükség:</p><ol><li>Tudni, hogy az eseménynek melyik csomópontba kell eljutnia.</li><li>Azonosítani a <code>Window</code>-ot, többablakos alkalmazásokban.</li><li>Tudni, milyen útvonalon kell végigmennie a jelenet és a csomópont között.</li></ol><p>Ezek a lépések az esemény kiváltásában. Az első lépést <strong>Target Selection</strong>-nek (<em>Cél kiválasztásnak</em>) nevezik. A második és harmadik lépést együtt hajtják végre egy folyamatban, amit <strong>Route Construction</strong>-nek (<em>Útvonal építés</em>) neveznek.</p><p>Ezek mindegyikén végigmegyünk, majd befejezésül végigmegyünk az események indításának módján.</p><h3 id="cel-kivalasztasa" tabindex="-1"><a class="header-anchor" href="#cel-kivalasztasa" aria-hidden="true">#</a> Cél kiválasztása</h3><p>A JavaFX a bekövetkezett esemény típusa és az eseményt létrehozó bemeneti eszköz alapján választja ki az esemény célpontját. Mivel a célpont kiválasztása típusfüggő, az alábbiakban áttekinthetjük az egyes eseménytípusok célpont-kiválasztását.</p><h3 id="utvonal-epites" tabindex="-1"><a class="header-anchor" href="#utvonal-epites" aria-hidden="true">#</a> Útvonal építés</h3><p>Új események esetén a cél csomópont létrehoz egy útvonalat Önmaga és az <code>Window</code> között.</p><p>A logika valami ilyesmit követ:</p><ul><li>Szerezd be az összes csomópontot innen a <code>Scene</code>:</li><li>A célcsomópont hozzáadása az útvonalhoz végpontként.</li><li>Ha a célnak van szülője, fűzzük hozzá a szülőcsomópontot az útvonalhoz.</li><li>Folytassuk a szülők hozzáadását, amíg el nem érek egy olyan csomóponthoz, amelynek nincs szülője.</li><li>Ez a gyökércsomópont.</li><li>Használjuk a gyökércsomópontot a <code>Scene</code> megszerzéséhez.</li></ul><h3 id="esemeny-rogzitese" tabindex="-1"><a class="header-anchor" href="#esemeny-rogzitese" aria-hidden="true">#</a> Esemény rögzítése</h3><p>A folyamat most az események lánca, ahol az esemény a lánc első elemenél kezdődik, majd fokozatosan halad végig minden csomóponton, mígnem elérjük a csomópontját.</p><p>Itt válik fontossá az esemény szűrők (<code>EventFilter</code>) és az eseménykezelők (<code>EventHandler</code>) közötti különbség. Ha még nem hallottál az esemény szűrőkről, azokat hozzá lehet adni bármely <code>EventTargethez</code> (csomópontok, jelenet, diagramok, feladatok stb.) az <code>addEventFilter()</code>-t.</p><p>Az esemény szűrők remekül használhatók a <code>Node</code>-ok viselkedésének irányítására, mivel a <code>SceneGraph</code> bejárása során a szülők először hajtják végre azokat.</p><figure><img src="`+o+`" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>Eseményszűrők bármely <code>EventTargethez</code> hozzáadhatók az <code>addEventFilter()</code> meghívásával a megfelelő <code>EventType</code> és <code>EventHandler</code> megadásával.</p><h2 id="futtathato-kod-definialasa-egy-eventhandler-ben" tabindex="-1"><a class="header-anchor" href="#futtathato-kod-definialasa-egy-eventhandler-ben" aria-hidden="true">#</a> Futtatható kód definiálása egy <code>EventHandler</code>-ben</h2><p>Amikor egy eseményre adott választ szeretnénk definiálni, akkor egy <code>EventHandler</code> objektumot kell használnunk.</p><h3 id="eventhandler-letrehozasa" tabindex="-1"><a class="header-anchor" href="#eventhandler-letrehozasa" aria-hidden="true">#</a> EventHandler létrehozása</h3><p>Ezt úgy tehetjük meg, hogy az <code>EventHandler</code>-t névtelen belső osztályként vagy <code>lambda</code>-kifejezésként definiáljuk.</p><h3 id="eventhandler-definialasa" tabindex="-1"><a class="header-anchor" href="#eventhandler-definialasa" aria-hidden="true">#</a> EventHandler definiálása</h3><p>Az <code>EventHandler</code> egy objektum egyetlen metódussal, amelyet felül kell írnunk, amikor példányosítjuk. Mivel az <code>EventHandler</code> interfész paraméterezett, meg kell adnunk, hogy milyen típusú eseményt kezelünk. Ebben az esetben egy <code>MouseEventet</code> fogunk használni.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token class-name">EventHandler</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">MouseEvent</span><span class="token punctuation">&gt;</span></span> eventHandler <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">EventHandler</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token annotation punctuation">@Override</span>
    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">handle</span><span class="token punctuation">(</span><span class="token class-name">MouseEvent</span> event<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token comment">//executable code</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="az-esemenykezelo-definiciojanak-csereje-egy-lambda-kifejezessel" tabindex="-1"><a class="header-anchor" href="#az-esemenykezelo-definiciojanak-csereje-egy-lambda-kifejezessel" aria-hidden="true">#</a> Az eseménykezelő definíciójának cseréje egy lambda kifejezéssel</h3><p>Az <code>EventHandler</code> egy funkcionális interfész (egy interfész egyetlen metódussal). A kényelem érdekében az <code>EventHandler</code> interfész <code>handle()</code> metódusa egy lambda kifejezéssel is megadható.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token class-name">EventHandler</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">MouseEvent</span><span class="token punctuation">&gt;</span></span> eventHandler <span class="token operator">=</span> event <span class="token operator">-&gt;</span> <span class="token punctuation">{</span>
    <span class="token comment">//executable code</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="esemenyszurok-esemenykezelok-hozzaadasa-es-eltavolitasa" tabindex="-1"><a class="header-anchor" href="#esemenyszurok-esemenykezelok-hozzaadasa-es-eltavolitasa" aria-hidden="true">#</a> Eseményszűrők, eseménykezelők hozzáadása és eltávolítása</h3><p>Amikor eseménykezelőt definiálunk és adunk hozzá egy csomóponthoz, meghatározzuk, hogy az adott eseménynek milyen típusától szeretnénk, ha a kódunk kiváltódna. Például, ha azt szeretnénk, hogy a kódunk a jelenetünk gyökércsomópontjának bármely egéreseményétől elinduljon, használhatjuk a <code>MouseEvent.ANY</code> eseménytípust.</p><p>Ha egy eseménykezelőt a kód egy későbbi pontján majd el akarunk távolítani, akkor meg kell tartanunk a létrehozott <code>EventHandler</code> objektumra való hivatkozást.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token comment">//define the handler</span>
<span class="token class-name">EventHandler</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">MouseEvent</span><span class="token punctuation">&gt;</span></span> eventHandler <span class="token operator">=</span> event <span class="token operator">-&gt;</span> <span class="token punctuation">{</span>
    <span class="token comment">//executable code</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>
<span class="token comment">//add the handler</span>
rootNode<span class="token punctuation">.</span><span class="token function">addEventHandler</span><span class="token punctuation">(</span><span class="token class-name">MouseEvent</span><span class="token punctuation">.</span><span class="token constant">ANY</span><span class="token punctuation">,</span> eventHandler<span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">//later remove the handler </span>
<span class="token comment">//this should be the same as defined above</span>
rootNode<span class="token punctuation">.</span><span class="token function">removeEventHandler</span><span class="token punctuation">(</span><span class="token class-name">MouseEvent</span><span class="token punctuation">.</span><span class="token constant">ANY</span><span class="token punctuation">,</span> eventHandler<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ugyanilyen egyszerű az eseményszűrők definiálása és eltávolítása az <code>addEventFilter()</code> és <code>removeEventFilter()</code> metódusok segítségével.</p><p>Néhány egyszerű dolgot azonban nem szabad elfelejteni:</p><ul><li>Ha egy eseménykezelőt adtál hozzá, akkor egy eseménykezelőt kell eltávolítanod (nem pedig egy szűrőt), és fordítva.</li><li>Az esemény típusának ugyanaznak kell lennie, amikor eltávolítod, mint amikor hozzáadod.</li></ul><p>Példa kód:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">package</span> <span class="token namespace">org<span class="token punctuation">.</span>vasvari<span class="token punctuation">.</span>helloworld</span><span class="token punctuation">;</span>

<span class="token keyword">import</span> <span class="token import"><span class="token namespace">javafx<span class="token punctuation">.</span>application<span class="token punctuation">.</span></span><span class="token class-name">Application</span></span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token import"><span class="token namespace">javafx<span class="token punctuation">.</span>event<span class="token punctuation">.</span></span><span class="token class-name">EventHandler</span></span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token import"><span class="token namespace">javafx<span class="token punctuation">.</span>scene<span class="token punctuation">.</span></span><span class="token class-name">Group</span></span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token import"><span class="token namespace">javafx<span class="token punctuation">.</span>scene<span class="token punctuation">.</span></span><span class="token class-name">Scene</span></span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token import"><span class="token namespace">javafx<span class="token punctuation">.</span>scene<span class="token punctuation">.</span>control<span class="token punctuation">.</span></span><span class="token class-name">Label</span></span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token import"><span class="token namespace">javafx<span class="token punctuation">.</span>scene<span class="token punctuation">.</span>control<span class="token punctuation">.</span></span><span class="token class-name">TextField</span></span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token import"><span class="token namespace">javafx<span class="token punctuation">.</span>scene<span class="token punctuation">.</span>input<span class="token punctuation">.</span></span><span class="token class-name">KeyEvent</span></span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token import"><span class="token namespace">javafx<span class="token punctuation">.</span>scene<span class="token punctuation">.</span>paint<span class="token punctuation">.</span></span><span class="token class-name">Color</span></span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token import"><span class="token namespace">javafx<span class="token punctuation">.</span>stage<span class="token punctuation">.</span></span><span class="token class-name">Stage</span></span><span class="token punctuation">;</span>

<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">JavaFX_EventFilter</span> <span class="token keyword">extends</span> <span class="token class-name">Application</span> <span class="token punctuation">{</span>

    <span class="token annotation punctuation">@Override</span>
    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">start</span><span class="token punctuation">(</span><span class="token class-name">Stage</span> primaryStage<span class="token punctuation">)</span> <span class="token keyword">throws</span> <span class="token class-name">Exception</span> <span class="token punctuation">{</span>
        <span class="token comment">// Címkék és szövegmezők hozzáadása a jelenethez</span>
        <span class="token class-name">Label</span> label1 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Label</span><span class="token punctuation">(</span><span class="token string">&quot;Nyomja meg a billentyűt &quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token class-name">TextField</span> textfield1 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">TextField</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token class-name">Label</span> label2 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Label</span><span class="token punctuation">(</span><span class="token string">&quot;Esemény szűrés &quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token class-name">TextField</span> textfield2 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">TextField</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

        <span class="token comment">// Elrendezés</span>
        label1<span class="token punctuation">.</span><span class="token function">setTranslateX</span><span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        label1<span class="token punctuation">.</span><span class="token function">setTranslateY</span><span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        label2<span class="token punctuation">.</span><span class="token function">setTranslateX</span><span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        label2<span class="token punctuation">.</span><span class="token function">setTranslateY</span><span class="token punctuation">(</span><span class="token number">150</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        textfield1<span class="token punctuation">.</span><span class="token function">setTranslateX</span><span class="token punctuation">(</span><span class="token number">250</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        textfield1<span class="token punctuation">.</span><span class="token function">setTranslateY</span><span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        textfield2<span class="token punctuation">.</span><span class="token function">setTranslateX</span><span class="token punctuation">(</span><span class="token number">250</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        textfield2<span class="token punctuation">.</span><span class="token function">setTranslateY</span><span class="token punctuation">(</span><span class="token number">150</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

        <span class="token comment">// Eseménykezelő objektum létrehozása</span>
        <span class="token class-name">EventHandler</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">KeyEvent</span><span class="token punctuation">&gt;</span></span> eventHandler <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">EventHandler</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
            <span class="token annotation punctuation">@Override</span>
            <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">handle</span><span class="token punctuation">(</span><span class="token class-name">KeyEvent</span> event<span class="token punctuation">)</span> <span class="token punctuation">{</span>
                textfield2<span class="token punctuation">.</span><span class="token function">setText</span><span class="token punctuation">(</span>event<span class="token punctuation">.</span><span class="token function">getEventType</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
                textfield1<span class="token punctuation">.</span><span class="token function">setText</span><span class="token punctuation">(</span>event<span class="token punctuation">.</span><span class="token function">getText</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
                event<span class="token punctuation">.</span><span class="token function">consume</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
            <span class="token punctuation">}</span>
        <span class="token punctuation">}</span><span class="token punctuation">;</span>

        <span class="token comment">// Esemény szűrő regisztrálása a szövegmezőn generált eseményhez</span>
        textfield1<span class="token punctuation">.</span><span class="token function">addEventFilter</span><span class="token punctuation">(</span><span class="token class-name">KeyEvent</span><span class="token punctuation">.</span><span class="token constant">ANY</span><span class="token punctuation">,</span> eventHandler<span class="token punctuation">)</span><span class="token punctuation">;</span>

        <span class="token comment">// Jelenet beállítása</span>
        <span class="token class-name">Group</span> root <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Group</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        root<span class="token punctuation">.</span><span class="token function">getChildren</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">addAll</span><span class="token punctuation">(</span>label1<span class="token punctuation">,</span> label2<span class="token punctuation">,</span> textfield1<span class="token punctuation">,</span> textfield2<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token class-name">Scene</span> scene <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Scene</span><span class="token punctuation">(</span>root<span class="token punctuation">,</span> <span class="token number">500</span><span class="token punctuation">,</span> <span class="token number">300</span><span class="token punctuation">,</span> <span class="token class-name">Color</span><span class="token punctuation">.</span><span class="token constant">WHEAT</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        primaryStage<span class="token punctuation">.</span><span class="token function">setScene</span><span class="token punctuation">(</span>scene<span class="token punctuation">)</span><span class="token punctuation">;</span>
        primaryStage<span class="token punctuation">.</span><span class="token function">setTitle</span><span class="token punctuation">(</span><span class="token string">&quot;Esemény szűrő hozzáadása&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        primaryStage<span class="token punctuation">.</span><span class="token function">show</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token function">launch</span><span class="token punctuation">(</span>args<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="esemenytipusok" tabindex="-1"><a class="header-anchor" href="#esemenytipusok" aria-hidden="true">#</a> Eseménytípusok</h2><p>Az események általában bemeneti eseményekre és JavaFX-specifikus eseményekre oszthatók. Az <code>ActionEvents</code> bemenetet igényelnek, de a bemeneti típusokat is átfogják, és a <strong>JavaFX</strong> belsőleg hozza létre őket, ezért ezeket nem a bemeneti, hanem a JavaFX-specifikus események közé soroljuk.</p><h3 id="az-operacios-rendszer-altal-generalt-bemeneti-esemenyek" tabindex="-1"><a class="header-anchor" href="#az-operacios-rendszer-altal-generalt-bemeneti-esemenyek" aria-hidden="true">#</a> Az operációs rendszer által generált (bemeneti) események</h3><p>A bemeneti események, például az egér-, billentyűzet- és gesztusesemények az alkalmazás szintje felett történnek, és az operációs rendszer továbbítja őket az alkalmazásunknak. A <strong>JavaFX</strong> háttérfolyamatai ezeket az információkat arra használják, hogy azonosítsák a megfelelő csomópontot, amelyen az eseményt végrehajtják.</p><figure><img src="`+l+`" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="billentyuesemenyek" tabindex="-1"><a class="header-anchor" href="#billentyuesemenyek" aria-hidden="true">#</a> Billentyűesemények</h3><p>A billentyűeseményeket az operációs rendszer generálja, amikor egy billentyű állapotát megváltoztatja - vagyis, lenyomják vagy felengedik. Ha egy billentyű hosszú ideig lenyomva marad, az operációs rendszer további billentyűeseményeket kezdeményezhet.</p><h3 id="egeresemenyek" tabindex="-1"><a class="header-anchor" href="#egeresemenyek" aria-hidden="true">#</a> Egeresemények</h3><p>A <code>MouseEvent</code> osztály meghatározza az egérkurzor pozíciójának vagy gombállapotainak bármilyen változását. Ahogyan a billentyűesemények esetében, ezeket az operációs rendszer szolgáltatja az alkalmazásnak, a felhasználó által beállított alapértelmezett egérviselkedési várakozások mellett.</p><h2 id="javafx-eredetu-esemenyek" tabindex="-1"><a class="header-anchor" href="#javafx-eredetu-esemenyek" aria-hidden="true">#</a> JavaFX-eredetű események</h2><p>A JavaFX képes saját események létrehozására és küldésére is. Ezeknek az eseményeknek három típusa van:</p><ul><li>Action Events</li><li>Worker Events</li><li>Edit, Modification and Sorting Events</li></ul><p>Minden típus lehetővé teszi a JavaFX számára, hogy funkcionalitást helyezzen a felhasználói felület fölé.</p><h3 id="action-events" tabindex="-1"><a class="header-anchor" href="#action-events" aria-hidden="true">#</a> Action Events</h3><p>A <code>Action Events</code> eseményeket úgy tervezték, hogy több bemeneti típusra is kiterjedjenek, és egyetlen végrehajtható kódot határozzanak meg, amelyet egy adott felhasználói művelet esetén használnak. Az olyan vezérlőelemek, mint a <code>TextField</code> és a gombok rendelkeznek <code>Action Event</code>-el.</p><p>Ez a funkcionalitás rétegezést biztosít a felhasználói felület felett egy olyan módon, amely több felhasználói bevitelt is felölel. Az akció a JavaFX rendszer nézőpontjából nézve egyfajta megerősítő felhasználói művelet. Példák erre:</p><ol><li>Gombra kattintás</li><li>Az Enter lenyomása, amikor a gomb van fókuszban</li><li>Az Enter lenyomása egy TextField-ben</li><li>Egy kapcsológomb felfegyverezése vagy lefegyverezése (billentyűzettel vagy egérrel)</li><li>Menügombra kattintás (vagy Enter leütése)</li></ol><p>Mindezekben az esetekben a <strong>JavaFX</strong> támogatja a következetes felhasználói elvárásokon alapuló műveletek végrehajtását, például egy űrlap elküldését az űrlap utolsó szövegmezőjének Enter billentyűjének megnyomásával, ahelyett, hogy a gombra kellene kattintani. Ily módon ugyanazt a végrehajtható kódot - ugyanazt az <code>EventHandler</code>-t - használhatjuk a szövegmező és a <code>Submit</code> gomb kezelésére is az alkalmazásunkban.</p><h3 id="hogyan-hasznaljuk-az-action-eventeket" tabindex="-1"><a class="header-anchor" href="#hogyan-hasznaljuk-az-action-eventeket" aria-hidden="true">#</a> Hogyan használjuk az Action Eventeket</h3><p>Leggyakrabban az <code>Action Event</code>-kezelőket a <code>setOnAction()</code> módszerrel adják hozzá. Ritkán van szükség több funkcionalitásra, ezért más eseménykezelők felülírása kevésbé fontos.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code>textField<span class="token punctuation">.</span><span class="token function">setOnAction</span><span class="token punctuation">(</span>event <span class="token operator">-&gt;</span> <span class="token punctuation">{</span>
    <span class="token comment">//event action defined with lambda</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Mint bármely eseménnyel, azokat beállíthatjuk az <code>addEventHandler()</code> és <code>addEventFilter()</code> metódusokkal.</p><p>Végül ezeket az <strong>FXML</strong>-ben a következő szintaxissal lehet definiálni:</p><div class="language-xml line-numbers-mode" data-ext="xml"><pre class="language-xml"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>TextField</span> <span class="token attr-name">onAction</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>#handleTextCommit<span class="token punctuation">&quot;</span></span> <span class="token attr-name"><span class="token namespace">fx:</span>id</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>textField<span class="token punctuation">&quot;</span></span><span class="token punctuation">/&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>A <strong>&quot;#&quot;</strong> szimbólum a <code>FXMLLoader</code>-nek azt az utasítást adja, hogy injektálja a <code>handleTextCommit(ActionEvent event)</code> metódust a <code>TextField</code> <code>onAction</code> tulajdonságába. A <code>handleTextCommit()</code> metódusnak jelen kell lennie a vezérlőben (a megfelelő <code>ActionEvent</code> argumentummal), különben betöltési kivétel (<em>load exception</em>) keletkezik.</p>`,103),i=[c];function k(u,d){return a(),s("div",null,i)}const v=n(p,[["render",k],["__file","lesson3e.html.vue"]]);export{v as default};
